class PIIDataMasker:
    """Utility to mask PII data for logging purposes."""

    @staticmethod
    def mask_email(email: str) -> str:
        if not email or "@" not in email:
            return "***"
        local, domain = email.split("@", 1)
        masked_local = local[0] + "*" * (len(local) - 1) if len(local) > 1 else "*"
        return f"{masked_local}@{domain}"

    @staticmethod
    def mask_phone(phone: str) -> str:
        if not phone or len(phone) < 4:
            return "***"
        return "*" * (len(phone) - 4) + phone[-4:]

    @staticmethod
    def mask_address(address: str) -> str:
        if not address:
            return "***"
        parts = address.split()
        if len(parts) <= 2:
            return "***"
        return "*** " + " ".join(parts[-2:])

    @classmethod
    def mask_user_data(cls, user_data: dict) -> dict:
        """Return a masked copy of user data safe for logging."""
        masked = user_data.copy()
        if "email" in masked:
            masked["email"] = cls.mask_email(masked["email"])
        if "phone_number" in masked:
            masked["phone_number"] = cls.mask_phone(masked["phone_number"])
        if "address" in masked:
            if isinstance(masked["address"], dict):
                addr_copy = masked["address"].copy()
                if "street" in addr_copy:
                    addr_copy["street"] = cls.mask_address(addr_copy["street"])
                masked["address"] = addr_copy
            elif isinstance(masked["address"], str):
                masked["address"] = cls.mask_address(masked["address"])
        if "ssn" in masked:
            masked["ssn"] = "***-**-" + masked["ssn"][-4:] if len(masked.get("ssn", "")) >= 4 else "***"
        return masked


class UserDataSQSPublisher:
    """
    SQS Publisher for user data messages containing PII.

    Supports both standard and FIFO queues. Messages are sent with
    appropriate message attributes for filtering and tracing.
    PII data is encrypted at rest via SQS server-side encryption (SSE)
    and in transit via HTTPS.
    """

    def __init__(
        self,
        queue_url: str,
        region_name: str = "us-east-1",
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
        use_fifo: bool = False,
        message_group_id: Optional[str] = None,
    ):
        self.queue_url = queue_url
        self.use_fifo = use_fifo
        self.message_group_id = message_group_id or "user-data-group"
        self.masker = PIIDataMasker()

        session_kwargs = {"region_name": region_name}
        if aws_access_key_id and aws_secret_access_key:
            session_kwargs["aws_access_key_id"] = aws_access_key_id
            session_kwargs["aws_secret_access_key"] = aws_secret_access_key

        session = boto3.Session(**session_kwargs)
        self.sqs_client = session.client("sqs")

    def _build_message_attributes(
        self, event_type: str, user_id: str, pii_fields: list
    ) -> dict:
        """Build SQS message attributes for filtering and metadata."""
        return {
            "EventType": {
                "DataType": "String",
                "StringValue": event_type,
            },
            "UserId": {
                "DataType": "String",
                "StringValue": user_id,
            },
            "ContainsPII": {
                "DataType": "String",
                "StringValue": "true",
            },
            "PIIFields": {
                "DataType": "String",
                "StringValue": ",".join(pii_fields),
            },
            "Timestamp": {
                "DataType": "String",
                "StringValue": datetime.utcnow().isoformat(),
            },
            "MessageVersion": {
                "DataType": "String",
                "StringValue": "1.0",
            },
        }

    def _identify_pii_fields(self, user_data: dict) -> list:
        """Identify which PII fields are present in the user data."""
        pii_field_names = {
            "email",
            "phone_number",
            "address",
            "ssn",
            "date_of_birth",
            "first_name",
            "last_name",
            "full_name",
            "credit_card",
            "bank_account",
            "drivers_license",
            "passport_number",
        }
        return [field for field in user_data.keys() if field in pii_field_names]

    def _build_message_body(
        self, user_data: dict, event_type: str, correlation_id: str
    ) -> dict:
        """Build the full message body envelope."""
        return {
            "message_id": str(uuid.uuid4()),
            "correlation_id": correlation_id,
            "event_type": event_type,
            "timestamp": datetime.utcnow().isoformat(),
            "version": "1.0",
            "source": "user-data-service",
            "data": user_data,
            "metadata": {
                "contains_pii": True,
                "pii_fields": self._identify_pii_fields(user_data),
                "data_classification": "confidential",
            },
        }

    def publish_user_data(
        self,
        user_data: dict,
        event_type: str = "USER_DATA_UPDATE",
        correlation_id: Optional[str] = None,
        delay_seconds: int = 0,
        deduplication_id: Optional[str] = None,
    ) -> dict:
        """
        Publish a user data message to SQS.

        Args:
            user_data: Dictionary containing user data (may include PII).
            event_type: Type of event (e.g., USER_CREATED, USER_UPDATED).
            correlation_id: Optional correlation ID for tracing.
            delay_seconds: Delay before message becomes visible (0-900 seconds).
            deduplication_id: Deduplication ID for FIFO queues.

        Returns:
            dict with message_id and status.
        """
        if not correlation_id:
            correlation_id = str(uuid.uuid4())

        user_id = user_data.get("user_id", "unknown")
        pii_fields = self._identify_pii_fields(user_data)

        message_body = self._build_message_body(
            user_data, event_type, correlation_id
        )
        message_attributes = self._build_message_attributes(
            event_type, user_id, pii_fields
        )

        send_kwargs = {
            "QueueUrl": self.queue_url,
            "MessageBody": json.dumps(message_body, default=str),
            "MessageAttributes": message_attributes,
            "DelaySeconds": delay_seconds,
        }

        if self.use_fifo:
            send_kwargs["MessageGroupId"] = self.message_group_id
            send_kwargs["MessageDeduplicationId"] = (
                deduplication_id or str(uuid.uuid4())
            )

        # Log masked data only - never log raw PII
        masked_data = self.masker.mask_user_data(user_data)
        logger.info(
            "Publishing user data message: event_type=%s, user_id=%s, "
            "correlation_id=%s, pii_fields=%s, masked_data=%s",
            event_type,
            user_id,
            correlation_id,
            pii_fields,
            json.dumps(masked_data),
        )

        try:
            response = self.sqs_client.send_message(**send_kwargs)
            message_id = response.get("MessageId")
            logger.info(
                "Successfully published message: message_id=%s, "
                "correlation_id=%s, user_id=%s",
                message_id,
                correlation_id,
                user_id,
            )
            return {
                "status": "success",
                "message_id": message_id,
                "correlation_id": correlation_id,
                "md5_of_body": response.get("MD5OfMessageBody"),
            }
        except ClientError as e:
            error_code = e.response["Error"]["Code"]
            error_message = e.response["Error"]["Message"]
            logger.error(
                "Failed to publish message: error_code=%s, error=%s, "
                "correlation_id=%s, user_id=%s",
                error_code,
                error_message,
                correlation_id,
                user_id,
            )
            raise

    def publish_user_created(self, user_data: dict, **kwargs) -> dict:
        """Publish a USER_CREATED event."""
        return self.publish_user_data(user_data, event_type="USER_CREATED", **kwargs)

    def publish_user_updated(self, user_data: dict, **kwargs) -> dict:
        """Publish a USER_UPDATED event."""
        return self.publish_user_data(user_data, event_type="USER_UPDATED", **kwargs)

    def publish_user_deleted(self, user_data: dict, **kwargs) -> dict:
        """Publish a USER_DELETED event."""
        return self.publish_user_data(user_data, event_type="USER_DELETED", **kwargs)

    def publish_user_pii_updated(self, user_data: dict, **kwargs) -> dict:
        """Publish a USER_PII_UPDATED event specifically for PII changes."""
        return self.publish_user_data(
            user_data, event_type="USER_PII_UPDATED", **kwargs
        )

    def publish_batch(
        self,
        messages: list,
        event_type: str = "USER_DATA_UPDATE",
    ) -> dict:
        """
        Publish a batch of user data messages (up to 10).

        Args:
            messages: List of dicts, each containing 'user_data' and
                      optionally 'correlation_id' and 'delay_seconds'.
            event_type: Default event type for all messages.

        Returns:
            dict with successful and failed message details.
        """
        if len(messages) > 10:
            raise ValueError("SQS batch size cannot exceed 10 messages.")

        entries = []
        for idx, msg in enumerate(messages):
            user_data = msg["user_data"]
            correlation_id = msg.get("correlation_id", str(uuid.uuid4()))
            delay_seconds = msg.get("delay_seconds", 0)
            msg_event_type = msg.get("event_type", event_type)
            user_id = user_data.get("user_id", "unknown")
            pii_fields = self._identify_pii_fields(user_data)

            message_body = self._build_message_body(
                user_data, msg_event_type, correlation_id
            )
            message_attributes = self._build_message_attributes(
                msg_event_type, user_id, pii_fields
            )

            entry = {
                "Id": str(idx),
                "MessageBody": json.dumps(message_body, default=str),
                "MessageAttributes": message_attributes,
                "DelaySeconds": delay_seconds,
            }

            if self.use_fifo:
                entry["MessageGroupId"] = self.message_group_id
                entry["MessageDeduplicationId"] = msg.get(
                    "deduplication_id", str(uuid.uuid4())
                )

            entries.append(entry)

            masked_data = self.masker.mask_user_data(user_data)
            logger.info(
                "Batch entry %d: event_type=%s, user_id=%s, masked_data=%s",
                idx,
                msg_event_type,
                user_id,
                json.dumps(masked_data),
            )

        try:
            response = self.sqs_client.send_message_batch(
                QueueUrl=self.queue_url, Entries=entries
            )

            successful = response.get("Successful", [])
            failed = response.get("Failed", [])

            logger.info(
                "Batch publish result: %d successful, %d failed",
                len(successful),
                len(failed),
            )

            if failed:
                for f in failed:
                    logger.error(
                        "Failed batch entry: id=%s, code=%s, message=%s",
                        f.get("Id"),
                        f.get("Code"),
                        f.get("Message"),
                    )

            return {
                "status": "completed",
                "successful_count": len(successful),
                "failed_count": len(failed),
                "successful": successful,
                "failed": failed,
            }
        except ClientError as e:
            logger.error("Batch publish failed: %s", e.response["Error"]["Message"])
            raise


